<template>
  <div class="container">

    <div class="row">
      <div class="col page-head">Stock Cards</div> 
    </div>
    
    <div class="row fn-bar">
      <div class="fn-btn pointer" v-on:click="$router.push({ name: 'Transactions'})">See Transactions</div>
      <div class="fn-btn pointer" v-on:click.prevent="printPreview()">Generate PDF</div>
    </div>

    <div class="card stock-info">
       <div class="row">
      
        <div class="col-6">
          <div class="row">
            <div class="col-5">จำนวนชนิดสินค้า</div>
            <div class="col-4 my-auto text-right">{{productsNum}}</div>
            <div class='col my-auto' style='padding-left: 10px;'>ชนิด</div>
          </div>
          <div class="row">
            <div class="col-5">มูลค่าสินค้าคงเหลือรวม</div>
            <div class="col-4 my-auto text-right">{{numberFormat(valueTotal)}}</div>
            <div class='col my-auto' style='padding-left: 10px;'> บาท</div>
          </div>
          <div class="row">
            <div class="col-6">จำนวนสินค้าคงเหลือรวม</div>
            <div class="col-3 my-auto text-right">{{numberFormat(stockTotal)}}</div>
            <div class='col my-auto' style='padding-left: 10px;'>ชิ้น</div>
          </div>
          <div class="row">
            <div class="col-6">จำนวนสินค้ารอจัดส่งรวม</div>
            <div class="col-3 my-auto text-right">{{numberFormat(tbdTotal)}}</div>
            <div class='col my-auto' style='padding-left: 10px;'>ชิ้น</div>
          </div>
        </div>
      </div>
    </div>
    
    <!-- List table -->
    <div class='card' style='font-size:0.7rem;'>
      <div class='flex-container table-header'>
        <div class="col-2">{{att.productId.label}}</div>
        <div class="col-2">{{att.productName.label}}</div>
        <div class="col-15 text-right">{{att.stockqty.label}}</div>
        <div class="col-15 text-right">{{att.valueAcc.label}}</div>
        <div class="col-15 text-right">{{att.valueAvg.label}}</div>
        <div class="col-15 text-right">{{att.tbdOrder.label}}</div>
        <div class="col-15 text-right">{{att.stocknet.label}}</div>

      </div>
      <div v-for="item in items" :key="item.productId">
        <!-- <button class="btn btn-block text-left p-0" > -->
          <div class='flex-container table-item' v-on:click="$router.push({ name: 'CardView', params: { id: item.productId , display:item.productId} })">
            <div class="col-2 my-auto">{{item.productId}}</div>
            <div class="col-2 my-auto">{{item.productName}}</div>
            <div class="col-15 my-auto text-right">{{item.stockqty}}</div>
            <div class="col-15 my-auto text-right">{{numberFormat(item.valueAcc)}}</div>
            <div class="col-15 my-auto text-right">{{numberFormat(item.valueAvg)}}</div>
            <div class="col-15 my-auto text-right">{{item.tbdOrder}}</div>
            <div class="col-15 my-auto text-right">{{item.stocknet}}</div>

          </div>
        <!-- </button> -->
      </div>
    </div>
    <!-- End of List -->

  </div>
</template>

<script>

import * as schema from '../assets/schema'

export default {
  data(){
    return {
      items:this.$store.state.cards,
      att:schema.cardAtt,
      productsNum:0,
      valueTotal:0,
      stockTotal:0,
      tbdTotal:0,
    }
  },
  methods:{
    numberFormat(num){
      return new Intl.NumberFormat('th-TH',{minimumFractionDigits: 2,maximumFractionDigits:2}).format(num)
    },
    sumInfo(){
      console.log('suminfo running')
      for(let key in this.items){
        this.productsNum++
        this.valueTotal = this.valueTotal + this.items[key].valueAcc
        this.stockTotal = this.stockTotal + this.items[key].stockqty 
        this.tbdTotal = this.tbdTotal + this.items[key].tbdOrder 
      }
    },
    printPreview(){
      let cards = JSON.parse(JSON.stringify(this.$store.state.cards))
      window.sessionStorage.setItem('cards',JSON.stringify(cards))
      window.open('/hunter-stock-card/print.html', '_blank')
    },
  },
  created(){
    this.sumInfo()
  }
}
</script>
